async function main() {
  console.log('🌱 Seeding 30 blog posts...');

  // Delete existing blog posts to avoid duplicates
  await prisma.blogPost.deleteMany({});
  console.log('🗑  Cleared existing blog posts');

  for (const post of POSTS) {
    await prisma.blogPost.create({
      data: {
        slug:          post.slug,
        title:         post.title,
        excerpt:       post.excerpt,
        content:       post.content,
        featuredImage: post.featuredImage,
        category:      post.category as 'BANGKOK' | 'PATTAYA' | 'THAILAND' | 'PHUKET' | 'KRABI',
        tags:          post.tags,
        status:        'PUBLISHED',
        publishedAt:   new Date(post.publishedAt),
        readingTimeMin: post.readingTimeMin,
        authorName:    'Werest Travel',
        authorTitle:   'Travel Expert',
      },
    });
    console.log(`  ✓ ${post.title}`);
  }

  console.log(`\n✅ Seeded ${POSTS.length} blog posts successfully!`);
}

main()
  .catch(e => { console.error(e); process.exit(1); })
  .finally(() => prisma.$disconnect());
